// Export the full system prompt builder
function buildSystemPrompt(knowledgeBase, userContext = {}) {
  const weekAwareness = userContext.currentWeek
    ? `\nThe user is currently in Week ${userContext.currentWeek} of the program. Only reference modules they have already completed (Week ${userContext.currentWeek} and earlier). For future modules, say "that's coming up" without teaching the content.\n`
    : "\nThe user's current week is unknown. Ask them where they are in the program if it is relevant to the conversation.\n";

  const userName = userContext.name
    ? `\nThe user's name is ${userContext.name}. Use it occasionally to personalize the conversation.\n`
    : "";

  return `${LAYER_1_IDENTITY}

${LAYER_2_VOICE}

${LAYER_3_METHODOLOGY}

${LAYER_3A_VISUAL_COACHING}

${LAYER_3B_SCRIPTURE_SCIENCE}

${LAYER_4_THEOLOGY}

${LAYER_4B_RETENTION}

${LAYER_4C_COMMUNITY}

═══ USER CONTEXT ═══
${weekAwareness}${userName}

═══ PROGRAM KNOWLEDGE BASE ═══
The following is a condensed summary of every module in the Unchained Vices program. Use this to answer questions about specific modules, reference frameworks, and guide clients through exercises.

${knowledgeBase}

${LAYER_5_SAFETY}`;
}

export { buildSystemPrompt };
